      await login(email, password);
      navigate('/dashboard');
    } catch {
      setError('Invalid credentials');
    }
  };

  return (
    <form onSubmit={handleSubmit}>
      <h1>Sign In</h1>
      <label htmlFor="email">Email</label>
      <input id="email" type="email" value={email} onChange={e => setEmail(e.target.value)} />
      <label htmlFor="password">Password</label>
      <input id="password" type="password" value={password} onChange={e => setPassword(e.target.value)} />
      {error && <div role="alert">{error}</div>}
      <button type="submit">Sign In</button>
    </form>
  );
}

import json
from typing import Any

def normalize_json(data: dict) -> str:
    """Canonical JSON: sorted keys, no whitespace, unicode escaped."""
    return json.dumps(data, sort_keys=True, separators=(',', ':'), ensure_ascii=True)

def denormalize_json(text: str) -> dict:
    return json.loads(text)

def normalize_email(email: str) -> str:
    local, domain = email.rsplit('@', 1)
    return f'{local.lower().strip()}@{domain.lower().strip()}'

def normalize_phone(phone: str) -> str:
    digits = ''.join(c for c in phone if c.isdigit())
    if len(digits) == 10:
        return f'+1{digits}'
    elif len(digits) == 11 and digits[0] == '1':
        return f'+{digits}'
    return digits

import datetime
import random

def generate_report(data: list[dict], config: dict) -> dict:
    report_id = f'RPT-{random.randint(1000,9999)}'
    timestamp = datetime.datetime.now().isoformat()
    total = sum(row.get('amount', 0) for row in data)
    avg = total / len(data) if data else 0
    categories = {}
    for row in data:
        cat = row.get('category', 'unknown')
        if cat not in categories:
            categories[cat] = {'count': 0, 'sum': 0}
        categories[cat]['count'] += 1
        categories[cat]['sum'] += row.get('amount', 0)
    return {
        'id': report_id,
        'timestamp': timestamp,
        'total': total,
        'average': avg,
        'categories': categories,
        'config': config,
    }

