import httpx
from typing import Any

class InventoryClient:
    def __init__(self, base_url: str):
        self.base_url = base_url

    def get_stock(self, product_code: str) -> dict[str, Any]:
        resp = httpx.get(f'{self.base_url}/api/stock/{product_code}')
        resp.raise_for_status()
        data = resp.json()
        return {
            'product_code': data['product_code'],
            'available_qty': data['available_qty'],
            'reserved_qty': data['reserved_qty'],
            'warehouse': data['warehouse']
        }

    def reserve_stock(self, product_code: str, quantity: int) -> dict[str, Any]:
        resp = httpx.post(
            f'{self.base_url}/api/stock/{product_code}/reserve',
            json={'quantity': quantity}
        )
        resp.raise_for_status()
        return resp.json()

    def list_low_stock(self, threshold: int = 100) -> list[dict]:
        resp = httpx.get(f'{self.base_url}/api/stock/low', params={'threshold': threshold})
        resp.raise_for_status()
        return resp.json()
